const row = $json;
const fields = Array.isArray(row.fields) ? [...row.fields].sort((a, b) => Number(a.fieldOrder) - Number(b.fieldOrder)) : [];
return [{ json: { jobId: row.jobId || null, organizationId: row.organizationId, knowledgeSourceId: row.knowledgeSourceId, sourceRecordId: row.sourceRecordId, normalizedRecord: { recordKey: row.recordKey, version: row.version, topic: row.topic, title: row.title, bodyMarkdown: row.bodyMarkdown || null, bodyJson: row.bodyJson || null, checksum: row.checksum || null, sourceFamily: row.sourceFamily, sourceType: row.sourceType, fields } } }];

const crypto = require('crypto');
const record = $json.normalizedRecord;
const chunks = [];
if (record.bodyMarkdown) {
  chunks.push({ chunkIndex: 0, chunkType: 'markdown-section', sourceFamily: record.sourceFamily, topic: record.topic, title: record.title, sectionPath: record.title, chunkText: record.bodyMarkdown, chunkHash: crypto.createHash('sha256').update(record.bodyMarkdown).digest('hex'), active: true });
}
return [{ json: { ...$json, chunks } }];
